const payload = $json.body || $json;
const transcript = String(payload.transcript || '').trim();
if (!transcript) {
  throw new Error('Missing transcript. Homepage voice widget must send transcript text.');
}
const language = payload.language || (/\u0600-\u06FF/.test(transcript) ? 'ar' : 'en');
const provider = String(payload.provider || 'browser').toLowerCase();
const sessionId = payload.sessionId || payload.session_id || `voice-${Date.now()}`;
return [{ json: {
  transcript,
  language,
  provider,
  session_id: sessionId,
  timestamp: payload.timestamp || new Date().toISOString(),
  vapi: payload.vapi || {},
  source_page: payload.source_page || null,
  page_url: payload.page_url || null,
  referrer_url: payload.referrer_url || null,
  utm_source: payload.utm_source || null,
  utm_medium: payload.utm_medium || null,
  utm_campaign: payload.utm_campaign || null,
  utm_term: payload.utm_term || null,
  utm_content: payload.utm_content || null
} }];
